package dev.harrison.rendacomcarro.finance;import dev.harrison.rendacomcarro.finance.application.InstallmentScheduleCalculator;import java.math.BigDecimal;import java.time.LocalDate;import org.junit.jupiter.api.Test;import static org.assertj.core.api.Assertions.assertThat;class InstallmentScheduleCalculatorTest {@Test void createsStructuredSchedule(){var result=new InstallmentScheduleCalculator().calculate(new BigDecimal("12000"),BigDecimal.ZERO,12,LocalDate.of(2026,8,10));assertThat(result).hasSize(12);assertThat(result.get(0).total()).isEqualByComparingTo("1000.00");assertThat(result.get(11).dueDate()).isEqualTo(LocalDate.of(2027,7,10));}}
